// Pick the 'Generated Report' library.
const drives=($input.first().json.value)||[];
const hit=drives.find(d=>(d.name||'').toLowerCase().includes('generated'))||drives[0]||null;
if(!hit) return [{json:{error:'no drives found'}}];
return [{json:{driveId:hit.id, driveName:hit.name}}];

// One item per WeeklyStatus_YYYY-MM-DD.html (skips the template + anything else).
const out=[];
for(const it of $input.all()){
  for(const f of (it.json.value||[])){
    const m=String(f.name||'').match(/^WeeklyStatus_(\d{4}-\d{2}-\d{2})\.html$/i);
    if(m) out.push({json:{id:f.id,name:f.name,week_ending:m[1]}});
  }
}
return out;

// Parse the report HTML: one row per <section class='project'>, then one idempotent
// upsert. Account matching happens in SQL: accounts name -> projects fallback; the raw
// client_directory name match is stored alongside for later linking.
const html=$json.data||'';
const meta=$('Each report file').item.json;
function strip(h){return String(h||'').replace(/<[^>]+>/g,' ').replace(/&middot;/g,' - ').replace(/&amp;/g,'&').replace(/&nbsp;/g,' ').replace(/&#39;/g,"'").replace(/\s+/g,' ').trim();}
const q=s=>(s===null||s===undefined||s==='')?'NULL':"'"+String(s).replace(/'/g,"''")+"'";
const secs=String(html).split(/<section class=['\"]project['\"]>/).slice(1);
const rows=[];
for(const s of secs){
  const title=strip((s.match(/<h2>([\s\S]*?)<\/h2>/)||[])[1]);
  if(!title)continue;
  const rag=((s.match(/pill pill-(red|amber|green|grey)/)||[])[1])||null;
  const lead=strip((s.match(/Customer lead:<\/span>([\s\S]*?)&middot;/)||[])[1]);
  const phase=strip((s.match(/Phase:([\s\S]*?)<\/p>/)||[])[1]);
  const summary=strip((s.match(/<div class=['\"]summary['\"]>([\s\S]*?)<\/div>/)||[])[1]);
  const block=t=>{const m=s.match(new RegExp('<h3>'+t+'<\\/h3>\\s*<p>([\\s\\S]*?)<\\/p>','i'));return m?strip(m[1]):null;};
  rows.push([meta.id,meta.week_ending,title,rag,lead,phase,summary,block('Highlights'),block('Lowlights'),block('Next week'),block('Risks and issues')]);
}
if(!rows.length)return {json:{sql:"SELECT 'no sections parsed' AS note;",file:meta.name,sections:0}};
const vals=rows.map(r=>'('+r.map((x,i)=>i===1?(q(x)+'::date'):q(x)).join(',')+')').join(',');
const sql="INSERT INTO weekly_reports (file_id,week_ending,project_title,account_id,account_name,rag,customer_lead,phase,summary,highlights,lowlights,next_week,risks) "+
"SELECT v.fid, v.week, v.title, "+
"COALESCE((SELECT id FROM accounts WHERE v.title ILIKE '%'||name||'%' ORDER BY length(name) DESC LIMIT 1),(SELECT p.account_id FROM projects p WHERE p.account_id IS NOT NULL AND (v.title ILIKE '%'||p.name||'%' OR p.name ILIKE '%'||split_part(v.title,' ',1)||'%') ORDER BY length(p.name) DESC LIMIT 1)), "+
"(SELECT name FROM client_directory WHERE v.title ILIKE '%'||name||'%' ORDER BY length(name) DESC LIMIT 1), "+
"v.rag, v.lead, v.phase, v.summary, v.hi, v.lo, v.nx, v.rk "+
"FROM (VALUES "+vals+") AS v(fid,week,title,rag,lead,phase,summary,hi,lo,nx,rk) "+
"ON CONFLICT (week_ending,project_title) DO UPDATE SET rag=EXCLUDED.rag, customer_lead=EXCLUDED.customer_lead, phase=EXCLUDED.phase, summary=EXCLUDED.summary, highlights=EXCLUDED.highlights, lowlights=EXCLUDED.lowlights, next_week=EXCLUDED.next_week, risks=EXCLUDED.risks, account_id=COALESCE(EXCLUDED.account_id, weekly_reports.account_id), account_name=COALESCE(EXCLUDED.account_name, weekly_reports.account_name);";
return {json:{sql,file:meta.name,sections:rows.length}};
